import axios from 'axios';
import { useEffect, useState } from 'react';

const clientId = 'YOUR_CLIENT_ID';
const clientSecret = 'YOUR_CLIENT_SECRET';
const redirectUri = 'http://localhost:3000/callback'; // adjust to your callback URL
const authorizationUrl = `https://example.com/oauth/authorize?response_type=token&client_id=${clientId}&redirect_uri=${redirectUri}`;

function App() {
  const [accessToken, setAccessToken] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.hash.slice(1));
    if (urlParams.has('access_token')) {
      setAccessToken(urlParams.get('access_token'));
    } else {
      window.location.href = authorizationUrl;
    }
  }, []);

  useEffect(() => {
    if (accessToken) {
      axios.post('/api/protected', { headers: { Authorization: `Bearer ${accessToken}` } })
        .then(response => console.log(response.data))
        .catch(error => setError(error.message));
    }
  }, [accessToken]);

  return (
    <div>
      {error && <p style={{ color: 'red' }}>{error}</p>}
      {accessToken && <p>Access Token: {accessToken}</p>}
    </div>
  );
}

export default App;